insert into bank_questions (question_key, subject_slug, page_id, page_name, source, qtype, marks, snapshot, answer_key)
values
('economics:2-6-production:mcq:a882f32e', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "Which shows an INTERNAL economy of scale?", "options": ["The council improving local roads", "A supermarket chain negotiating bulk discounts from suppliers", "A new university opening nearby", "Suppliers clustering around a big factory"]}'::jsonb, '{"answer": 1, "explain": "Purchasing economies come from the firm''s OWN size. The other three are EXTERNAL — outside the firm''s control and available to all local firms."}'::jsonb),
('economics:2-6-production:mcq:ffa4b2be', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "A firm doubles a shipping container''s length and width. Volume rises 8× but the base area (which sets the cost) only rises 4×. This is the economy of...", "options": ["Managerial", "Increased dimensions", "Financial", "Marketing"]}'::jsonb, '{"answer": 1, "explain": "Economies of increased dimension — why global firms build ever-bigger container ships to cut per-unit shipping costs."}'::jsonb),
('economics:2-6-production:mcq:e8a35c18', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "As a firm grows very large, information takes longer to pass up and down the chain and workers feel unsupervised. Average costs start to RISE. This is...", "options": ["A purchasing economy", "Kaizen", "A diseconomy of scale", "An external economy of scale"]}'::jsonb, '{"answer": 2, "explain": "Diseconomies of scale — communication problems, lost motivation, lost direction and bottlenecks can make a firm TOO big."}'::jsonb),
('economics:2-6-production:mcq:126ce68d', 'economics', 'economics:2-6-production', '2.6 Production', 'mcq', 'mcq', 1, '{"question": "A firm installs a fast new machine in one section, but the next stage of production cannot process the extra output. The result is...", "options": ["Higher productivity overall", "Lower fixed costs", "A production bottleneck — the extra output is wasted", "An economy of scale"]}'::jsonb, '{"answer": 2, "explain": "Output from one stage must match what the next stage can handle — otherwise the money spent on the machine achieves no extra usable output."}'::jsonb),
('economics:2-6-production:tf:bc74bb85', 'economics', 'economics:2-6-production', '2.6 Production', 'tf', 'tf', 1, '{"question": "Production and productivity mean the same thing."}'::jsonb, '{"answer": false, "explain": "Production = total output. Productivity = output per unit of input (efficiency). Real MCQs and 2-markers punish mixing them up."}'::jsonb),
('economics:2-6-production:tf:0eb1e2d8', 'economics', 'economics:2-6-production', '2.6 Production', 'tf', 'tf', 1, '{"question": "Individuals cannot be producers of goods and services."}'::jsonb, '{"answer": false, "explain": "FALSE — self-employed plumbers and builders are individual producers. This is the NOT-true statement from a real MCQ."}'::jsonb),
('economics:2-6-production:tf:6649da79', 'economics', 'economics:2-6-production', '2.6 Production', 'tf', 'tf', 1, '{"question": "An increase in productivity will always lead to a fall in average costs."}'::jsonb, '{"answer": true, "explain": "More output per unit of input means each unit costs less — the only ''always'' guaranteed result (profit and total costs depend on other things)."}'::jsonb),
('economics:2-6-production:tf:4e5ffcd5', 'economics', 'economics:2-6-production', '2.6 Production', 'tf', 'tf', 1, '{"question": "Average revenue equals the selling price."}'::jsonb, '{"answer": true, "explain": "AR = TR ÷ quantity = (P × Q) ÷ Q = P. A handy shortcut in calculations."}'::jsonb),
('economics:2-6-production:tf:825c2cb7', 'economics', 'economics:2-6-production', '2.6 Production', 'tf', 'tf', 1, '{"question": "Economies of scale mean total costs fall as a firm grows."}'::jsonb, '{"answer": false, "explain": "AVERAGE (unit) costs fall — total costs usually rise with output. The real mark scheme gives nothing for ''changes in total costs''."}'::jsonb),
('economics:2-6-production:tf:bccfd66e', 'economics', 'economics:2-6-production', '2.6 Production', 'tf', 'tf', 1, '{"question": "External economies of scale are available to all firms in an area, regardless of their size."}'::jsonb, '{"answer": true, "explain": "That''s what makes them EXTERNAL — outside any single firm''s control: infrastructure, local training facilities, clustering suppliers."}'::jsonb),
('economics:2-6-production:tf:f09eafe0', 'economics', 'economics:2-6-production', '2.6 Production', 'tf', 'tf', 1, '{"question": "A firm that grows larger will always enjoy lower average costs."}'::jsonb, '{"answer": false, "explain": "Growing too big can bring DISeconomies — communication problems, lost motivation, bottlenecks — that push average costs back UP."}'::jsonb),
('economics:2-6-production:tf:2c718033', 'economics', 'economics:2-6-production', '2.6 Production', 'tf', 'tf', 1, '{"question": "Persistent losses will eventually force a business to close."}'::jsonb, '{"answer": true, "explain": "Losses may be expected early in a business''s life, but long-term the revenue must cover the costs — otherwise the business fails."}'::jsonb),
('economics:2-6-production:learn:35aaa94d', 'economics', 'economics:2-6-production', '2.6 Production', 'learn', 'mcq', 1, '{"readingTitle": "Producers and production", "reading": "<p><strong>Production is the total output of goods and services produced in a given time period</strong> by a firm, an industry or a country. Both halves of that definition earn marks: total output AND a time period.</p>\n<h4>Who are the producers? (all three can be producers!)</h4>\n<ul>\n<li><strong>Individuals</strong> — self-employed tradespeople like plumbers and builders (a real MCQ: a self-employed plumber is an individual as a PRODUCER).</li>\n<li><strong>Firms</strong> — partnerships, private and public limited companies, even charities.</li>\n<li><strong>The government</strong> — a producer of services such as health and education, including services the private sector will not provide.</li>\n</ul>\n<h4>Goods vs services</h4>\n<ul>\n<li><strong>Goods</strong> are tangible — they have a physical form (made in the secondary sector from raw materials).</li>\n<li><strong>Services</strong> are <strong>intangible</strong> — the key difference (a real MCQ). Both still need labour, capital and specialisation!</li>\n</ul>\n<h4>Why production matters for the economy</h4>\n<ul>\n<li>It meets society''s wants and needs — if production falls, supply falls, prices rise and choice shrinks.</li>\n<li>More production usually means <strong>more jobs</strong> (helping the low-unemployment objective) — unless the extra output comes from machinery instead.</li>\n<li>Output becomes <strong>income</strong>: higher production → higher incomes → higher standard of living. At national level, rising production IS economic growth.</li>\n<li>More output to sell → higher profits → reinvestment and growth, and possibly <strong>economies of scale</strong>.</li>\n<li>⚠ One thing increased production does NOT usually deliver: greater <strong>environmental sustainability</strong> — more output tends to use more resources (a real MCQ trap).</li>\n</ul>", "question": "Plumbers who work for themselves are examples of individuals as...", "options": ["Employers", "Competitors", "Consumers only", "Producers"]}'::jsonb, '{"answer": 3, "explain": "Individuals can absolutely be producers — the self-employed plumber produces a service. ''Individuals cannot be producers'' is the NOT-true statement in a real MCQ."}'::jsonb),
('economics:2-6-production:learn:84e43a6e', 'economics', 'economics:2-6-production', '2.6 Production', 'learn', 'mcq', 1, '{"readingTitle": "Productivity — and how it differs from production", "reading": "<p><strong>Productivity measures the EFFICIENCY of the factors of production: output per unit of input</strong> — most commonly output per worker. It is NOT the same as production (total output). The spec rewards precise use of both terms, and mixing them up costs marks on real MCQs.</p>\n<h4>The Charlie vs Gabi test (a real MCQ)</h4>\n<ul>\n<li>Charlie raises PRODUCTION 10% — more total output, but maybe just from more workers, so costs per unit may not fall.</li>\n<li>Gabi raises PRODUCTIVITY 10% — the same inputs make more output, so average costs FALL and the business becomes more <strong>competitive</strong>.</li>\n</ul>\n<h4>How producers increase productivity</h4>\n<ul>\n<li><strong>Specialisation / division of labour</strong> — workers repeating specialised tasks become faster and more skilled.</li>\n<li><strong>Training and education</strong> — more skilled workers produce more.</li>\n<li><strong>Investment in capital equipment</strong> — machines that take over or speed up production.</li>\n<li><strong>Kaizen</strong> — continuous small improvements suggested by workers at every level.</li>\n<li>⚠ NOT \"employ more workers\" — that raises production, not output per worker!</li>\n</ul>\n<h4>Why higher productivity matters</h4>\n<ul>\n<li><strong>Firms</strong>: lower average costs → cut prices to compete, or keep prices and enjoy higher profit margins; less waste; faster response to the market.</li>\n<li><strong>Workers</strong>: more productive workers can earn more — though workers whose tasks can be automated may struggle.</li>\n<li><strong>Government/economy</strong>: productivity growth drives economic growth and international competitiveness (more exports, fewer imports).</li>\n</ul>\n<p><strong>Careful:</strong> higher productivity ALWAYS cuts average costs — but not necessarily total costs or profit (a real MCQ: the only guaranteed result is a fall in average costs).</p>", "question": "A business could increase PRODUCTIVITY by...", "options": ["Employing more workers", "Training its workers to be more skilled", "Producing more by working longer hours", "Buying more raw materials"]}'::jsonb, '{"answer": 1, "explain": "Productivity is output PER worker (or per unit of input). More workers or longer hours raise production, not productivity — the confusion real examiners flagged."}'::jsonb),
('economics:2-6-production:learn:1a18c93d', 'economics', 'economics:2-6-production', '2.6 Production', 'learn', 'mcq', 1, '{"readingTitle": "Costs, revenue, profit and loss — the calculations", "reading": "<p>This topic carries the paper''s calculation battery. Learn the formulas cold:</p>\n<ul>\n<li><strong>Total cost (TC)</strong> = total fixed costs + total variable costs.</li>\n<li><strong>Average cost (AC)</strong> = total cost ÷ quantity produced — cost per unit, the firm''s efficiency gauge (falling AC = more efficient).</li>\n<li><strong>Total revenue (TR)</strong> = price × quantity sold.</li>\n<li><strong>Average revenue (AR)</strong> = total revenue ÷ quantity — which equals the PRICE.</li>\n<li><strong>Profit (or loss)</strong> = total revenue − total cost. Positive = profit; negative = LOSS (say so!).</li>\n</ul>\n<h4>The definitions behind them</h4>\n<ul>\n<li><strong>Fixed costs</strong> — do not vary with output (rent, salaries, machinery): £12,000 of rent is £12,000 whether you make 0 items or 1,500.</li>\n<li><strong>Variable costs</strong> — rise and fall with output (raw materials, ingredients).</li>\n</ul>\n<h4>Why each matters to producers</h4>\n<ul>\n<li><strong>Costs</strong> must stay below revenue long-term to survive; lower costs mean price competitiveness and more profit retained.</li>\n<li><strong>Revenue</strong> — steady revenue attracts investors, reassures suppliers and workers.</li>\n<li><strong>Profit</strong> — a source of internal finance for growth, a signal that attracts resources and investors, a reward to the owners. Losses can be expected early in a business''s life, but persistent losses eventually force closure.</li>\n<li>Higher prices mean higher profit per unit — the INCENTIVE for producers to expand production (how profit links to supply).</li>\n</ul>\n<p><strong>The official OCR Misconception box:</strong> revenue and profit are NOT the same — never use the words interchangeably.</p>", "question": "A firm''s total revenue is £500,000 from selling 200 units. Its average revenue (= price) is...", "options": ["£2,500", "£100,000", "£2,000", "£250"]}'::jsonb, '{"answer": 0, "explain": "AR = TR ÷ quantity = £500,000 ÷ 200 = £2,500 — and average revenue always equals the selling price. A real exam calculation."}'::jsonb),
('economics:2-6-production:learn:a3bc91ce', 'economics', 'economics:2-6-production', '2.6 Production', 'learn', 'mcq', 1, '{"readingTitle": "Economies of scale — internal, external and DIS-economies", "reading": "<p><strong>Economies of scale are the fall in AVERAGE (unit) cost as the scale of production rises.</strong> Precision matters: ''falling costs'' or ''falling total costs'' scores nothing — it must be average/unit costs.</p>\n<h4>INTERNAL economies (from the firm''s own growth) — know several, not just one</h4>\n<ul>\n<li><strong>Purchasing</strong> — bulk-buying discounts (the one everyone remembers — it''s one of many!).</li>\n<li><strong>Technical</strong> — affording specialist equipment and automation.</li>\n<li><strong>Increased dimensions</strong> — double a container''s length and width and volume rises 8× while base cost rises 4×.</li>\n<li><strong>Division of labour</strong> — splitting work so employees specialise.</li>\n<li><strong>Financial</strong> — big firms are lower-risk, so cheaper loans, plus share issues.</li>\n<li><strong>Managerial</strong> — employing specialist managers for each department (a real MCQ).</li>\n<li><strong>Marketing</strong> — spreading big advertising spend over many branches (radio-advert MCQ).</li>\n<li><strong>Risk-bearing</strong> — a wider range of products/markets so one failure doesn''t sink the firm.</li>\n<li><strong>R&amp;D</strong> — affording continuous innovation.</li>\n</ul>\n<h4>EXTERNAL economies (outside the firm''s control, available to ALL local firms)</h4>\n<ul>\n<li>Improved <strong>infrastructure</strong> — better roads/rail cut everyone''s transport costs (the Letusprovide 2-marker).</li>\n<li><strong>Education and training</strong> facilities — university partnerships (Oxford/Cambridge attracting tech firms).</li>\n<li><strong>Clustering / location</strong> — suppliers locating nearby (Nissan Sunderland''s just-in-time park; Silicon Valley). ''Location'' is the external one in a real MCQ list.</li>\n</ul>\n<h4>DISeconomies of scale — when growing too big RAISES average costs</h4>\n<ul>\n<li><strong>Communication problems</strong> — information moves slowly through a big organisation.</li>\n<li><strong>Loss of motivation</strong> — workers feel isolated; supervision weakens.</li>\n<li><strong>Loss of direction</strong> — department managers pull against company goals.</li>\n<li><strong>Production bottlenecks</strong> — one stage produces more than the next can handle.</li>\n</ul>", "question": "As a business grows it can afford to employ specialist staff for each department. Which economy of scale is this?", "options": ["Managerial", "Increased dimensions", "Risk-bearing", "Marketing"]}'::jsonb, '{"answer": 0, "explain": "Specialist managers for production, finance, marketing etc. = managerial economies. A real exam MCQ — learn all nine types, not just bulk-buying."}'::jsonb),
('economics:2-6-production:misc:080e5efa', 'economics', 'economics:2-6-production', '2.6 Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"To increase productivity, employ more workers.\"</p><p><strong>✅ The correct idea:</strong> That increases PRODUCTION (total output), not PRODUCTIVITY (output per worker) — the confusion examiners reported on the real ''explain one way to increase productivity'' 2-marker. Productivity rises when the SAME inputs produce more: specialisation, training, investment in technology and capital equipment, or better motivation (bonuses, team building). Keep the two definitions welded on: production = total output in a time period; productivity = output per unit of input. The Charlie/Gabi MCQ tests exactly this — the productivity-raiser gains competitiveness; the production-raiser might not.</p>", "question": "\"Explain one way in which a business could increase productivity.\" Which answer scores?", "options": ["Employ more workers to make more output", "Buy more raw materials", "Train workers so each produces more in the same time", "Open longer hours"]}'::jsonb, '{"answer": 2, "explain": "Only training raises output PER WORKER. The other three raise total output while productivity stays the same (or falls)."}'::jsonb),
('economics:2-6-production:misc:9050c820', 'economics', 'economics:2-6-production', '2.6 Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Economies of scale are when costs fall as a firm grows.\"</p><p><strong>✅ The correct idea:</strong> Imprecise — and the real mark scheme explicitly gives NOTHING for answers that refer only to costs or total costs. Economies of scale are the fall in AVERAGE (unit) cost as the scale of production rises. Total costs usually RISE as output grows; it''s the cost of each unit that falls. The same trap appears in MCQs: a table showed total costs rising from £24 to £56, but the AVERAGE cost fell from £24 to £14 — candidates who missed the word ''average'' picked the wrong answer. Always write ''average cost'' or ''unit cost'', and check whether a table question asks about totals or averages.</p>", "question": "Output 1 → TC £24. Output 4 → TC £56. What happened to AVERAGE cost?", "options": ["It rose by £32", "It rose by £14", "It fell by £10 (from £24 to £14)", "It stayed the same"]}'::jsonb, '{"answer": 2, "explain": "AC at 1 = £24; AC at 4 = £56 ÷ 4 = £14 — a fall of £10. ''Many candidates gave +£32 as they had not noticed the word average.''"}'::jsonb),
('economics:2-6-production:misc:cae7aaac', 'economics', 'economics:2-6-production', '2.6 Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"More revenue means more profit.\"</p><p><strong>✅ The correct idea:</strong> The official OCR Misconception box: revenue and profit are NOT the same. Profit = total revenue − total costs, so a rise in TR only raises profit if TR rises by MORE than TC. Ask how the revenue rose: a higher price might cut future sales; selling more output means more variable costs; the extra revenue may go to shareholders rather than the business. The real ''evaluate the extent to which an increase in total revenue will lead to more profit'' 6-marker rewarded exactly this — candidates who assumed TR up = profit up, or used the two words interchangeably, stalled at the bottom of the mark scheme.</p>", "question": "A firm''s total revenue rises by £10,000 and its total costs rise by £12,000. Its profit...", "options": ["Rises by £10,000", "Rises by £2,000", "Stays the same", "Falls by £2,000"]}'::jsonb, '{"answer": 3, "explain": "Profit = TR − TC. Revenue up does NOT mean profit up — costs rose faster here."}'::jsonb),
('economics:2-6-production:misc:4447ff2a', 'economics', 'economics:2-6-production', '2.6 Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"The factor market is the primary sector, and the product market is the secondary/tertiary sector.\"</p><p><strong>✅ The correct idea:</strong> Another official OCR Misconception box, from the Asian Hornet interdependence question. The FACTOR market is where the factors of production (labour, land, capital) are bought and sold — in every sector. The PRODUCT market is where finished goods and services are sold to buyers. They are INTERDEPENDENT: when the Hornet cuts crop production, producers need fewer workers (factor market); those workers are also consumers, so with less income they buy fewer products (product market). Many real candidates confused the factor market with the primary sector and scored nothing.</p>", "question": "The factor market is where...", "options": ["Finished goods are manufactured", "Raw materials are extracted (farming, mining)", "Factors of production like labour are bought and sold", "Only primary-sector firms operate"]}'::jsonb, '{"answer": 2, "explain": "Factor market ≠ primary sector — the official Misconception box. It''s the market for labour, land and capital across the whole economy."}'::jsonb),
('economics:2-6-production:misc:3d4917b3', 'economics', 'economics:2-6-production', '2.6 Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Cost of specialisation for a small business? The workers get bored.\"</p><p><strong>✅ The correct idea:</strong> Incomplete — and a real exemplar answer exactly like this scored 0. The question asked for a cost to the BUSINESS, so you must carry the chain through to the business: workers get bored → labour turnover rises → the small business pays higher recruitment and training costs it can ill afford. The same stakeholder discipline ran through this paper: ''advantages for WESTUMBRIA'' (the region — answers about the small businesses scored nothing), and ''the extent to which specialisation benefits WORKERS in Oxbria'' (answers about firms not credited). Underline the stakeholder before writing.</p>", "question": "\"Explain one cost FOR A SMALL BUSINESS of specialisation by its workers.\" The real 0-mark answer said ''boredom in workers''. What was missing?", "options": ["A longer description of boredom", "A diagram", "The word ''specialisation''", "The link to the business — bored workers leave, raising recruitment and training costs"]}'::jsonb, '{"answer": 3, "explain": "The cost must land on the business, not the workers. Bored workers → higher turnover → recruitment/training costs the small business must pay."}'::jsonb),
('economics:2-6-production:misc:27c38eca', 'economics', 'economics:2-6-production', '2.6 Production', 'misc', 'mcq', 1, '{"readingTitle": "Misconception check", "reading": "<p><strong>❌ Common misconception:</strong> \"Profit is money the owners can spend on advertising and hiring staff — that''s its advantage.\"</p><p><strong>✅ The correct idea:</strong> The real ''advantages of making a profit'' 6-marker exposed this: many candidates ''simply did not understand what profit can be used for''. Better answers treated profit as (1) a source of internal finance for new capital and expansion, (2) a signal of success that attracts investors, lenders and scarce resources, (3) the survival condition — it lets the business stay in business, and (4) a REWARD and income to the owners, improving their material wellbeing. And remember the biggest discriminator on that question wasn''t the list — it was CONTEXT: answers that never mentioned the actual business (gardens, in that case) were capped in Level 1–2.</p>", "question": "What was the most significant discriminator on the real ''advantages of profit'' 6-marker?", "options": ["Writing more than a page", "Using the word profit many times", "Applying the answer to the actual business in the extract", "Drawing a diagram"]}'::jsonb, '{"answer": 2, "explain": "The examiner report: lack of application of knowledge to the scenario kept good analysis out of the top half of the mark scheme."}'::jsonb),
('economics:2-6-production:tips:999e3538', 'economics', 'economics:2-6-production', '2.6 Production', 'tips', 'mcq', 1, '{"readingTitle": "calculation — The calculation battery: units, labels and the Own Figure Rule", "reading": "<p>This paper has more calculations than any other topic. The formulas are easy — the marks are lost on details:</p>\n<ul>\n<li><strong>Units matter</strong>: the Asian Hornet average was £26.1m ÷ 3 = <strong>£8.7 MILLION</strong> — real candidates who wrote ''8.7'' or ''£8.7'' lost a mark for forgetting the million.</li>\n<li><strong>£ sign matters</strong>: £3,500 average cost and £2,500 per unit both required the £ sign for full marks.</li>\n<li><strong>Say ''loss''</strong>: Air Madeira''s −£76,000 needed the minus sign or the word loss.</li>\n<li><strong>Include ALL the costs</strong>: the garden profit (£3,850) required adding the £11,400 design costs to the building costs first — the most common error was leaving out the fixed costs.</li>\n<li><strong>Show working</strong>: the Own Figure Rule rescues 1 mark after a slip — but only if the method is visible (Mia''s wage: £30,000 + £2,400 + £3,000 = £35,400).</li>\n</ul>", "question": "Nest destruction costs: France £10.5m, Italy £8m, UK £7.6m. The full-marks average is...", "options": ["£8.7 million", "£8.70", "8.7", "£26.1 million"]}'::jsonb, '{"answer": 0, "explain": "(10.5 + 8 + 7.6) ÷ 3 = 8.7 — but the mark scheme docked candidates who ''forgot to add million to the answer''."}'::jsonb),
('economics:2-6-production:tips:49844a75', 'economics', 'economics:2-6-production', '2.6 Production', 'tips', 'mcq', 1, '{"readingTitle": "sixmarker — Analyse 6-markers: context is the discriminator", "reading": "<p>Two Analyse 6-markers here (advantages of profit; why more production matters for Oxbria) — and both examiner reports say the same thing:</p>\n<ul>\n<li><strong>Application to the scenario was ''the most significant discriminator''</strong>: 4/6 needed knowledge applied to Amir and Nina; 5–6 needed understanding of the extract''s specific elements. Excellent generic analysis was held in Level 1–2 without it.</li>\n<li>Build 2 developed chains: profit → source of finance for new capital → the business expands → economic sustainability; production up → profits and incomes up → spending in Oxbria rises → more jobs elsewhere too (the multiplier).</li>\n<li>Watch exclusions: the Oxbria question said ''OTHER THAN an increase in demand for labour'' — leading with the excluded point wastes your best chain.</li>\n<li>No conclusion needed — Analyse has no evaluation marks.</li>\n</ul>\n<p>OCR publishes a Teacher Support Guide on 6-mark questions (''A guide to 6-mark questions'') — the page''s model answers follow it.</p>", "question": "\"OTHER THAN an increase in demand for labour, analyse why more production matters for Oxbria.\" Your first chain should be about...", "options": ["Something else — e.g. higher profits leading to investment and higher living standards", "A definition of Oxbria", "The weather", "The increase in demand for labour"]}'::jsonb, '{"answer": 0, "explain": "The question excludes the labour-demand point. Profits→investment, economies of scale, growth and living standards are the credited routes."}'::jsonb),
('economics:2-6-production:tips:8270bb64', 'economics', 'economics:2-6-production', '2.6 Production', 'tips', 'mcq', 1, '{"readingTitle": "evaluate — Evaluate: meet the question''s EXTRA requirement", "reading": "<p>This paper''s official Assessment-for-learning box: ''evaluate'' is frequently accompanied by an extra requirement — <em>the extent to which</em>, <em>the costs</em>, <em>the advantages</em>, <em>the importance</em> — and you must evaluate WITHIN that requirement.</p>\n<ul>\n<li>''The extent to which the Hornet harms SOCIAL SUSTAINABILITY'' — both ''extent'' and ''social sustainability'' had to be directly addressed for more than 2 evaluation marks.</li>\n<li>''The importance for CONSUMERS of ALASA''s inelastic supply'' — the importance to the consumer had to anchor the judgement (a real script scored 5/6 for lacking exactly that final step).</li>\n<li>''The extent to which TR leads to more profit'' — the winning answers wrote profit = TR − TC and judged WHEN the link holds (TR rising faster than TC).</li>\n</ul>\n<h4>How real answers scored</h4>\n<p>⚠️ <strong>Level 2:</strong> both sides + ''so overall it depends'' — a judgement, but not supported.</p>\n<p>✅ <strong>Level 3:</strong> a judgement that answers the question''s own frame: \"Overall, higher revenue only means more profit to the extent that it grows faster than costs — which is likely here because the fixed costs stay unchanged.\"</p>", "question": "On the Hornet question, what TWO things had to be directly addressed for more than 2 evaluation marks?", "options": ["Diagrams and formulas", "OPEC and PES", "''The extent to which'' and ''social sustainability''", "France and Italy"]}'::jsonb, '{"answer": 2, "explain": "The mark scheme''s NB line names both. Evaluate inside the question''s exact frame, not generically."}'::jsonb),
('economics:2-6-production:tips:6f7703cd', 'economics', 'economics:2-6-production', '2.6 Production', 'tips', 'mcq', 1, '{"readingTitle": "diagrams — Drawing curves from data: the plotting rules", "reading": "<p>Three draw-from-data questions here (ALASA''s supply, Firm A''s supply, Periff''s next-auction supply). The recurring rules:</p>\n<ul>\n<li><strong>Plot the exact points</strong> from the table — check the axis scales first (''marks can easily be gained, but just as easily lost'').</li>\n<li><strong>Join the points point-to-point</strong>, ruler or freehand — a line of best fit is capped at 1 mark, and so are unjoined points.</li>\n<li>A generic upward-sloping line with no points plotted scores 0 — the data must be used.</li>\n<li>One point wrong = max 1; more than one wrong = 0 (Periff rules).</li>\n<li>Extensions (e.g. down to zero) are ignored — they don''t cost you anything.</li>\n<li>A few real candidates ''invented their own numbers'' — everything comes from the extract''s table.</li>\n</ul>", "question": "You plot all five points correctly but draw a smooth line of best fit that misses two of them. You score...", "options": ["2 marks", "3 marks", "1 mark of the 2", "0 marks"]}'::jsonb, '{"answer": 2, "explain": "The mark schemes repeatedly cap best-fit lines at 1 — the curve must pass through the plotted points."}'::jsonb),
