('economics:2-6-production:match:41b634b7', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Production”?", "options": ["The total output of goods and services produced in a given time period", "Output per unit of input — a measure of the efficiency of the factors of production", "Costs that do not vary with the level of output, like rent and salaries", "Costs that rise and fall with output, like raw materials"]}'::jsonb, '{"answer": 0, "explain": "“Production” means: The total output of goods and services produced in a given time period"}'::jsonb),
('economics:2-6-production:match:9fa9d662', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Productivity”?", "options": ["Costs that do not vary with the level of output, like rent and salaries", "Costs that rise and fall with output, like raw materials", "Total fixed costs plus total variable costs", "Output per unit of input — a measure of the efficiency of the factors of production"]}'::jsonb, '{"answer": 3, "explain": "“Productivity” means: Output per unit of input — a measure of the efficiency of the factors of production"}'::jsonb),
('economics:2-6-production:match:772d7704', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Fixed costs”?", "options": ["Costs that rise and fall with output, like raw materials", "Costs that do not vary with the level of output, like rent and salaries", "Total fixed costs plus total variable costs", "Total cost divided by quantity produced — the cost per unit"]}'::jsonb, '{"answer": 1, "explain": "“Fixed costs” means: Costs that do not vary with the level of output, like rent and salaries"}'::jsonb),
('economics:2-6-production:match:9f512937', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Variable costs”?", "options": ["Total fixed costs plus total variable costs", "Total cost divided by quantity produced — the cost per unit", "Price multiplied by quantity sold", "Costs that rise and fall with output, like raw materials"]}'::jsonb, '{"answer": 3, "explain": "“Variable costs” means: Costs that rise and fall with output, like raw materials"}'::jsonb),
('economics:2-6-production:match:295735f0', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Total cost”?", "options": ["Total cost divided by quantity produced — the cost per unit", "Price multiplied by quantity sold", "Total fixed costs plus total variable costs", "Total revenue divided by quantity — always equals the price"]}'::jsonb, '{"answer": 2, "explain": "“Total cost” means: Total fixed costs plus total variable costs"}'::jsonb),
('economics:2-6-production:match:85307a88', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Average cost”?", "options": ["Price multiplied by quantity sold", "Total cost divided by quantity produced — the cost per unit", "Total revenue divided by quantity — always equals the price", "Total revenue minus total cost — negative means a loss"]}'::jsonb, '{"answer": 1, "explain": "“Average cost” means: Total cost divided by quantity produced — the cost per unit"}'::jsonb),
('economics:2-6-production:match:e0ab478f', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Total revenue”?", "options": ["Total revenue divided by quantity — always equals the price", "Total revenue minus total cost — negative means a loss", "The fall in average (unit) cost as the scale of production rises", "Price multiplied by quantity sold"]}'::jsonb, '{"answer": 3, "explain": "“Total revenue” means: Price multiplied by quantity sold"}'::jsonb),
('economics:2-6-production:match:e966eac3', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Average revenue”?", "options": ["Total revenue minus total cost — negative means a loss", "The fall in average (unit) cost as the scale of production rises", "Total revenue divided by quantity — always equals the price", "Cost advantages outside the firm''s control, available to all firms in an area or industry"]}'::jsonb, '{"answer": 2, "explain": "“Average revenue” means: Total revenue divided by quantity — always equals the price"}'::jsonb),
('economics:2-6-production:match:24b0ed73', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Profit or loss”?", "options": ["The fall in average (unit) cost as the scale of production rises", "Cost advantages outside the firm''s control, available to all firms in an area or industry", "Rising average costs when an organisation grows too large", "Total revenue minus total cost — negative means a loss"]}'::jsonb, '{"answer": 3, "explain": "“Profit or loss” means: Total revenue minus total cost — negative means a loss"}'::jsonb),
('economics:2-6-production:match:b2354ff3', 'economics', 'economics:2-6-production', '2.6 Production', 'match', 'mcq', 1, '{"question": "Which definition matches the key term “Economies of scale”?", "options": ["The fall in average (unit) cost as the scale of production rises", "Cost advantages outside the firm''s control, available to all firms in an area or industry", "Rising average costs when an organisation grows too large", "Continuous small improvements suggested by workers at every level"]}'::jsonb, '{"answer": 0, "explain": "“Economies of scale” means: The fall in average (unit) cost as the scale of production rises"}'::jsonb),
